"""
Secure OAuth 2.0 Authorization Server with proper redirect URI validation.

Instead of dangerous substring/prefix matching, we support multiple environments
by allowing clients to register multiple exact redirect URIs.
"""

import hashlib
import secrets
import time
import urllib.parse
from dataclasses import dataclass, field
from typing import Optional
from flask import Flask, request, jsonify, redirect, render_template_string

app = Flask(__name__)


@dataclass
class OAuthClient:
    client_id: str
    client_secret_hash: str
    client_name: str
    # Multiple exact redirect URIs - one per environment
    registered_redirect_uris: list[str] = field(default_factory=list)
    allowed_scopes: list[str] = field(default_factory=list)


@dataclass
class AuthorizationCode:
    code: str
    client_id: str
    redirect_uri: str
    user_id: str
    scopes: list[str]
    expires_at: float
    code_challenge: Optional[str] = None
    code_challenge_method: Optional[str] = None


@dataclass
class AccessToken:
    token: str
    client_id: str
    user_id: str
    scopes: list[str]
    expires_at: float


# In-memory stores (use a database in production)
clients: dict[str, OAuthClient] = {}
authorization_codes: dict[str, AuthorizationCode] = {}
access_tokens: dict[str, AccessToken] = {}


def hash_secret(secret: str) -> str:
    return hashlib.sha256(secret.encode()).hexdigest()


def validate_redirect_uri_secure(client: OAuthClient, redirect_uri: str) -> bool:
    """
    SECURE redirect URI validation using EXACT string matching.

    Per RFC 6749 Section 3.1.2.3 and OAuth 2.0 Security Best Current Practice
    (RFC 9700), redirect URIs MUST be compared using exact string matching.

    To support multiple environments (dev, staging, prod), clients register
    multiple complete redirect URIs rather than using dangerous prefix matching.

    WHY NOT prefix/substring matching?
    - An attacker could use: https://legit-app.com.attacker.com/steal
    - Or: https://legit-app.com/callback/../../../attacker-path
    - This leads to authorization code/token theft (open redirect)
    """
    # Normalize the URI for comparison
    parsed = urllib.parse.urlparse(redirect_uri)

    # Reject URIs with fragments (per RFC 6749)
    if parsed.fragment:
        return False

    # Reject non-HTTPS URIs (except localhost for development)
    if parsed.scheme != "https" and parsed.hostname not in ("localhost", "127.0.0.1"):
        return False

    # EXACT match against registered URIs - the only secure approach
    return redirect_uri in client.registered_redirect_uris


