def register_client(
    client_name: str,
    redirect_uris: list[str],
    scopes: list[str] | None = None,
) -> tuple[str, str]:
    """
    Register a new OAuth client with multiple exact redirect URIs.

    Example - supporting multiple environments securely:
        redirect_uris=[
            "https://dev.myapp.com/oauth/callback",
            "https://staging.myapp.com/oauth/callback",
            "https://myapp.com/oauth/callback",
            "http://localhost:3000/oauth/callback",  # local dev
        ]
    """
    client_id = secrets.token_urlsafe(24)
    client_secret = secrets.token_urlsafe(48)

    validated_uris = []
    for uri in redirect_uris:
        parsed = urllib.parse.urlparse(uri)
        if not parsed.scheme or not parsed.netloc:
            raise ValueError(f"Invalid redirect URI: {uri}")
        if parsed.fragment:
            raise ValueError(f"Redirect URI must not contain fragment: {uri}")
        validated_uris.append(uri)

    client = OAuthClient(
        client_id=client_id,
        client_secret_hash=hash_secret(client_secret),
        client_name=client_name,
        registered_redirect_uris=validated_uris,
        allowed_scopes=scopes or ["read"],
    )
    clients[client_id] = client
    return client_id, client_secret


def generate_authorization_code(
    client_id: str,
    redirect_uri: str,
    user_id: str,
    scopes: list[str],
    code_challenge: Optional[str] = None,
    code_challenge_method: Optional[str] = None,
) -> str:
    code = secrets.token_urlsafe(32)
    authorization_codes[code] = AuthorizationCode(
        code=code,
        client_id=client_id,
        redirect_uri=redirect_uri,
        user_id=user_id,
        scopes=scopes,
        expires_at=time.time() + 600,  # 10 minutes
        code_challenge=code_challenge,
        code_challenge_method=code_challenge_method,
    )
    return code


def generate_access_token(client_id: str, user_id: str, scopes: list[str]) -> str:
    token = secrets.token_urlsafe(32)
    access_tokens[token] = AccessToken(
        token=token,
        client_id=client_id,
        user_id=user_id,
        scopes=scopes,
        expires_at=time.time() + 3600,  # 1 hour
    )
    return token


def verify_pkce(code_verifier: str, code_challenge: str, method: str) -> bool:
    if method == "S256":
        digest = hashlib.sha256(code_verifier.encode("ascii")).digest()
        computed = (
            secrets.token_urlsafe(0).__class__
            .__bases__[0]
            .__subclasses__()[0]
            # Actually, let's just do it properly:
        )
        import base64
        computed = base64.urlsafe_b64encode(digest).rstrip(b"=").decode("ascii")
        return secrets.compare_digest(computed, code_challenge)
    elif method == "plain":
        return secrets.compare_digest(code_verifier, code_challenge)
    return False


def verify_pkce_s256(code_verifier: str, code_challenge: str) -> bool:
    import base64
    digest = hashlib.sha256(code_verifier.encode("ascii")).digest()
    computed = base64.urlsafe_b64encode(digest).rstrip(b"=").decode("ascii")
    return secrets.compare_digest(computed, code_challenge)


