@app.route("/authorize", methods=["GET"])
def authorize_get():
    client_id = request.args.get("client_id")
    redirect_uri = request.args.get("redirect_uri")
    response_type = request.args.get("response_type")
    scope = request.args.get("scope", "read")
    state = request.args.get("state", "")
    code_challenge = request.args.get("code_challenge", "")
    code_challenge_method = request.args.get("code_challenge_method", "")

    if not client_id or not redirect_uri or response_type != "code":
        return jsonify({"error": "invalid_request"}), 400

    client = clients.get(client_id)
    if not client:
        return jsonify({"error": "invalid_client", "error_description": "Unknown client"}), 400

    # SECURE: Exact match redirect URI validation
    if not validate_redirect_uri_secure(client, redirect_uri):
        # Per RFC 6749 4.1.2.1: Do NOT redirect back if redirect_uri is invalid
        return jsonify({
            "error": "invalid_request",
            "error_description": (
                "redirect_uri does not exactly match any registered URI. "
                "Register each environment's URI separately for security."
            ),
            "registered_uris_hint": [
                uri[:20] + "..." for uri in client.registered_redirect_uris
            ],
        }), 400

    requested_scopes = scope.split()
    if not all(s in client.allowed_scopes for s in requested_scopes):
        return _redirect_with_error(redirect_uri, "invalid_scope", state)

    return render_template_string(
        LOGIN_TEMPLATE,
        client_name=client.client_name,
        client_id=client_id,
        redirect_uri=redirect_uri,
        scopes=scope,
        state=state,
        response_type=response_type,
        code_challenge=code_challenge,
        code_challenge_method=code_challenge_method,
    )


@app.route("/authorize", methods=["POST"])
def authorize_post():
    client_id = request.form.get("client_id")
    redirect_uri = request.form.get("redirect_uri")
    scope = request.form.get("scope", "read")
    state = request.form.get("state", "")
    action = request.form.get("action")
    username = request.form.get("username")
    code_challenge = request.form.get("code_challenge", "")
    code_challenge_method = request.form.get("code_challenge_method", "")

    client = clients.get(client_id)
    if not client:
        return jsonify({"error": "invalid_client"}), 400

    # Re-validate redirect_uri on POST (defense in depth)
    if not validate_redirect_uri_secure(client, redirect_uri):
        return jsonify({"error": "invalid_request", "error_description": "Invalid redirect_uri"}), 400

    if action == "deny":
        return _redirect_with_error(redirect_uri, "access_denied", state)

    # In production, authenticate the user properly
    user_id = username  # Simplified for demonstration

    scopes = scope.split()
    code = generate_authorization_code(
        client_id=client_id,
        redirect_uri=redirect_uri,
        user_id=user_id,
        scopes=scopes,
        code_challenge=code_challenge or None,
        code_challenge_method=code_challenge_method or None,
    )

    params = {"code": code}
    if state:
        params["state"] = state

    return redirect(_build_redirect_url(redirect_uri, params))


@app.route("/token", methods=["POST"])
def token():
    grant_type = request.form.get("grant_type")

    if grant_type == "authorization_code":
        return _handle_authorization_code_grant()
    elif grant_type == "client_credentials":
        return _handle_client_credentials_grant()
    else:
        return jsonify({"error": "unsupported_grant_type"}), 400


def _handle_authorization_code_grant():
    code = request.form.get("code")
    redirect_uri = request.form.get("redirect_uri")
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")
    code_verifier = request.form.get("code_verifier")

    if not code or not redirect_uri or not client_id:
        return jsonify({"error": "invalid_request"}), 400

    auth_code = authorization_codes.get(code)
    if not auth_code:
        return jsonify({"error": "invalid_grant", "error_description": "Invalid or expired code"}), 400

    # Validate authorization code
    if auth_code.client_id != client_id:
        authorization_codes.pop(code, None)
        return jsonify({"error": "invalid_grant"}), 400

    if auth_code.redirect_uri != redirect_uri:
        authorization_codes.pop(code, None)
        return jsonify({"error": "invalid_grant", "error_description": "redirect_uri mismatch"}), 400

    if auth_code.expires_at < time.time():
        authorization_codes.pop(code, None)
        return jsonify({"error": "invalid_grant", "error_description": "Code expired"}), 400

    # Verify PKCE or client secret
    if auth_code.code_challenge:
        if not code_verifier:
            return jsonify({"error": "invalid_request", "error_description": "code_verifier required"}), 400
        method = auth_code.code_challenge_method or "plain"
        if method == "S256":
            if not verify_pkce_s256(code_verifier, auth_code.code_challenge):
                authorization_codes.pop(code, None)
                return jsonify({"error": "invalid_grant", "error_description": "PKCE verification failed"}), 400
        elif method == "plain":
            if not secrets.compare_digest(code_verifier, auth_code.code_challenge):
                authorization_codes.pop(code, None)
                return jsonify({"error": "invalid_grant"}), 400
    else:
        # Require client_secret if no PKCE
        client = clients.get(client_id)
        if not client or not client_secret:
            return jsonify({"error": "invalid_client"}), 401
        if hash_secret(client_secret) != client.client_secret_hash:
            return jsonify({"error": "invalid_client"}), 401

    # Single use: remove authorization code
    authorization_codes.pop(code, None)

    access_token = generate_access_token(
        client_id=client_id,
        user_id=auth_code.user_id,
        scopes=auth_code.scopes,
    )

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": 3600,
        "scope": " ".join(auth_code.scopes),
    })


def _handle_client_credentials_grant():
    client_id = request.form.get("client_id")
    client_secret = request.form.get("client_secret")

    if not client_id or not client_secret:
        return jsonify({"error": "invalid_client"}), 401

    client = clients.get(client_id)
    if not client or hash_secret(client_secret) != client.client_secret_hash:
        return jsonify({"error": "invalid_client"}), 401

    scope = request.form.get("scope", "read")
    scopes = scope.split()
    if not all(s in client.allowed_scopes for s in scopes):
        return jsonify({"error": "invalid_scope"}), 400

    access_token = generate_access_token(
        client_id=client_id,
        user_id="__client__",
        scopes=scopes,
    )

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": 3600,
        "scope": " ".join(scopes),
    })


@app.route("/introspect", methods=["POST"])
def introspect():
    token = request.form.get("token")
    token_data = access_tokens.get(token)

    if not token_data or token_data.expires_at < time.time():
        return jsonify({"active": False})

    return jsonify({
        "active": True,
        "client_id": token_data.client_id,
        "username": token_data.user_id,
        "scope": " ".join(token_data.scopes),
        "exp": int(token_data.expires_at),
    })


@app.route("/register", methods=["POST"])
def register_client_endpoint():
    """Dynamic client registration endpoint."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "invalid_request"}), 400

    client_name = data.get("client_name", "Unknown App")
    redirect_uris = data.get("redirect_uris", [])
    scopes = data.get("scopes", ["read"])

    if not redirect_uris:
        return jsonify({"error": "invalid_request", "error_description": "At least one redirect_uri required"}), 400

    try:
        client_id, client_secret = register_client(
            client_name=client_name,
            redirect_uris=redirect_uris,
            scopes=scopes,
        )
    except ValueError as e:
        return jsonify({"error": "invalid_request", "error_description": str(e)}), 400

    return jsonify({
        "client_id": client_id,
        "client_secret": client_secret,
        "client_name": client_name,
        "redirect_uris": redirect_uris,
        "message": (
            "Each redirect URI is registered exactly. "
            "Register all environment-specific URIs for multi-env support."
        ),
    }), 201


def _build_redirect_url(base_uri: str, params: dict) -> str:
    parsed = urllib.parse.urlparse(base_uri)
    query = urllib.parse.parse_qs(parsed.query)
    for k, v in params.items():
        query[k] = [v]
    new_query = urllib.parse.urlencode(query, doseq=True)
    return urllib.parse.urlunparse(parsed._replace(query=new_query))


def _redirect_with_error(redirect_uri: str, error: str, state: str):
    params = {"error": error}
    if state:
        params["state"] = state
    return redirect(_build_redirect_url(redirect_uri, params))


